CREATE TABLE `gambar_varian_produks` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `varian_produk_id` bigint unsigned NOT NULL,
  `url` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `alt` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `urutan` int NOT NULL DEFAULT '0',
  `utama` tinyint(1) NOT NULL DEFAULT '0',
  `shopee_image_id` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `gambar_varian_produks_varian_produk_id_foreign` (`varian_produk_id`),
  CONSTRAINT `gambar_varian_produks_varian_produk_id_foreign` FOREIGN KEY (`varian_produk_id`) REFERENCES `varian_produks` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=581 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
