LOCK TABLES `halamans` WRITE;
/*!40000 ALTER TABLE `halamans` DISABLE KEYS */;
INSERT INTO `halamans` VALUES (1,'contact','Hubungi Auraquina','Customer Care','Saluran resmi untuk pertanyaan pesanan, ukuran, dan bantuan belanja Auraquina.','[{\"body\": [\"WhatsApp admin: 0811-3662-636.\", \"Email: hello@auraquina.com.\", \"Lokasi operasional: Malang, East Java, Indonesia.\"], \"heading\": \"Kontak Utama\"}, {\"body\": [\"Senin sampai Sabtu, pukul 09.00 - 17.00 WIB.\", \"Pesan yang masuk di luar jam kerja akan dibalas pada hari kerja berikutnya.\"], \"heading\": \"Jam Layanan\"}]',1,0,'2026-06-27 05:32:42','2026-06-27 05:32:42'),(2,'shipping-policy','Kebijakan Pengiriman','Shipping Policy','Informasi pengiriman, waktu proses, dan tanggung jawab penerimaan pesanan.','[{\"body\": [\"Pesanan diproses setelah pembayaran diterima atau terverifikasi.\", \"Pesanan yang masuk pada hari kerja akan diproses secepatnya sesuai antrean.\"], \"heading\": \"Proses Pesanan\"}, {\"body\": [\"Estimasi pengiriman mengikuti layanan kurir yang dipilih saat checkout.\", \"Pastikan nama penerima, nomor telepon, dan alamat lengkap sudah benar sebelum menyelesaikan pesanan.\"], \"heading\": \"Pengiriman\"}, {\"body\": [\"Keterlambatan akibat kendala kurir, cuaca, atau force majeure berada di luar kendali Auraquina.\", \"Jika paket diterima dalam kondisi bermasalah, segera hubungi customer care dengan nomor pesanan Anda.\"], \"heading\": \"Catatan Penting\"}]',1,1,'2026-06-27 05:32:42','2026-06-27 05:32:42'),(3,'return-exchange','Return & Exchange','After Sales Policy','Panduan pengajuan penukaran, retur, dan penanganan kendala pasca pembelian.','[{\"body\": [\"Pengajuan dilakukan maksimal 7 hari setelah pesanan diterima.\", \"Produk harus dalam kondisi bersih, belum dipakai, dan label masih terpasang.\"], \"heading\": \"Syarat Pengajuan\"}, {\"body\": [\"Anda dapat mengajukan penukaran ukuran, retur, atau komplain pesanan dari detail pesanan.\", \"Sertakan penjelasan yang jelas agar tim kami dapat meninjau lebih cepat.\"], \"heading\": \"Jenis Kendala\"}, {\"body\": [\"Setelah request dikirim, tim Auraquina akan meninjau dan menghubungi Anda melalui kanal yang tersedia.\", \"Persetujuan penggantian atau refund mengikuti hasil verifikasi kondisi barang dan riwayat pesanan.\"], \"heading\": \"Proses Review\"}]',1,2,'2026-06-27 05:32:42','2026-06-27 05:32:42'),(4,'faq','Frequently Asked Questions','FAQ','Jawaban ringkas untuk pertanyaan yang paling sering ditanyakan pelanggan Auraquina.','[{\"body\": [\"Bisa. Anda tetap dapat checkout sebagai guest.\"], \"heading\": \"Apakah bisa belanja tanpa akun?\"}, {\"body\": [\"Setelah order dibuat, Anda dapat membuka detail pesanan dari tautan yang diberikan atau melalui akun jika Anda login.\"], \"heading\": \"Bagaimana mengecek status pesanan?\"}, {\"body\": [\"Gunakan fitur after-sales pada detail pesanan untuk mengajukan penukaran atau komplain.\"], \"heading\": \"Bagaimana jika ukuran tidak sesuai?\"}]',1,3,'2026-06-27 05:32:42','2026-06-27 05:32:42'),(5,'about','Tentang Auraquina','About Us','Auraquina menghadirkan modest fashion dengan siluet tenang, material nyaman, dan estetika yang timeless.','[{\"body\": [\"Auraquina dirancang untuk perempuan yang menemukan keindahan dalam kesederhanaan.\", \"Setiap koleksi berangkat dari kebutuhan akan busana yang mudah dipakai, tetap anggun, dan relevan lebih lama.\"], \"heading\": \"Brand Story\"}, {\"body\": [\"Kami memilih palet warna yang lembut, potongan yang bersih, dan detail yang tidak berlebihan.\", \"Fokus kami adalah kenyamanan, kepraktisan, dan rasa percaya diri saat dipakai setiap hari.\"], \"heading\": \"Filosofi Produk\"}]',1,4,'2026-06-27 05:32:42','2026-06-27 05:32:42'),(6,'size-guide','Size Guide','Panduan Ukuran','Gunakan panduan ini untuk memilih ukuran yang paling nyaman sebelum checkout.','[{\"body\": [\"Ukur lingkar dada, pinggang, pinggul, dan panjang baju dengan posisi tubuh rileks.\", \"Bandingkan hasilnya dengan detail ukuran pada halaman produk.\"], \"heading\": \"Cara Mengukur\"}, {\"body\": [\"Jika Anda berada di antara dua ukuran, pilih berdasarkan preferensi fit yang diinginkan.\", \"Untuk bahan yang jatuh dan longgar, pertimbangkan ruang gerak tambahan saat memilih ukuran.\"], \"heading\": \"Tips Memilih Ukuran\"}]',1,5,'2026-06-27 05:32:42','2026-06-27 05:32:42'),(7,'privacy-policy','Kebijakan Privasi','Privacy Policy','Penjelasan singkat tentang data yang kami kumpulkan dan cara Auraquina menggunakannya.','[{\"body\": [\"Kami menggunakan data yang Anda berikan saat membuat akun, checkout, atau menghubungi customer care.\"], \"heading\": \"Data yang Dikumpulkan\"}, {\"body\": [\"Data digunakan untuk memproses pesanan, membantu layanan pelanggan, dan mengirim pembaruan yang relevan dengan transaksi Anda.\"], \"heading\": \"Penggunaan Data\"}, {\"body\": [\"Auraquina berupaya menjaga kerahasiaan data pelanggan dan membatasi akses hanya untuk kebutuhan operasional yang relevan.\"], \"heading\": \"Perlindungan Data\"}]',1,6,'2026-06-27 05:32:42','2026-06-27 05:32:42'),(8,'terms-conditions','Syarat & Ketentuan','Terms & Conditions','Ketentuan dasar yang mengatur penggunaan website dan transaksi di Auraquina.','[{\"body\": [\"Dengan menggunakan website ini, Anda setuju memberikan informasi yang akurat saat membuat akun atau melakukan checkout.\"], \"heading\": \"Penggunaan Website\"}, {\"body\": [\"Pesanan dianggap diterima setelah data checkout lengkap dan sistem berhasil membuat nomor pesanan.\", \"Auraquina berhak meninjau atau membatalkan pesanan jika ditemukan kendala stok, data, atau alasan operasional lain yang sah.\"], \"heading\": \"Pemesanan\"}, {\"body\": [\"Harga dan ketersediaan produk dapat berubah sewaktu-waktu mengikuti kondisi koleksi yang tersedia.\"], \"heading\": \"Harga dan Ketersediaan\"}]',1,7,'2026-06-27 05:32:42','2026-06-27 05:32:42');
/*!40000 ALTER TABLE `halamans` ENABLE KEYS */;
