--
-- Table structure for table `produks`
--

DROP TABLE IF EXISTS `produks`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `produks` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `kategori_id` bigint unsigned NOT NULL,
  `nama` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `slug` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `deskripsi` text COLLATE utf8mb4_unicode_ci,
  `deskripsi_singkat` text COLLATE utf8mb4_unicode_ci,
  `harga` int NOT NULL,
  `harga_coret` int DEFAULT NULL,
  `sku` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `berat` int NOT NULL DEFAULT '0',
  `bahan` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `perawatan` text COLLATE utf8mb4_unicode_ci,
  `info_model` text COLLATE utf8mb4_unicode_ci,
  `aktif` tinyint(1) NOT NULL DEFAULT '1',
  `unggulan` tinyint(1) NOT NULL DEFAULT '0',
  `badge` enum('baru','terlaris','terbatas','preorder') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `urutan` int NOT NULL DEFAULT '0',
  `shopee_item_id` bigint unsigned DEFAULT NULL,
  `shopee_shop_id` bigint unsigned DEFAULT NULL,
  `shopee_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `rating_star` decimal(4,2) DEFAULT NULL,
  `stock_display` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `source_categories` json DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `produks_slug_unique` (`slug`),
  UNIQUE KEY `produks_sku_unique` (`sku`),
  UNIQUE KEY `produks_shopee_item_id_unique` (`shopee_item_id`),
  KEY `produks_kategori_id_foreign` (`kategori_id`),
  KEY `produks_aktif_index` (`aktif`),
  CONSTRAINT `produks_kategori_id_foreign` FOREIGN KEY (`kategori_id`) REFERENCES `kategoris` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=47 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `produks`
--

LOCK TABLES `produks` WRITE;
/*!40000 ALTER TABLE `produks` DISABLE KEYS */;
INSERT INTO `produks` VALUES (5,1,'Mahyra Dress . Gamis Rayon Homedress','mahyra-dress-gamis-rayon-homedress','MAHYRA DRESS\n\nMOHON DIBACA DETAILNYA DULU SEBELUM ORDER\n\nDetail Dress \n- Panjang Dress -+ 140 cm \n- Lingkar Dada -+ 110 cm \n- Panjang Lengan -+ 55 cm \n- Lingkar Ketiak -+ 50 cm\n\nMaterial Rayon Viscose Premium\nBusui friendly kancing\nSaku dibagian kanan\n\nToleransi ukuran 1-2 cm karena produksi massal \nPerbedaan warna 98% tergantung cahaya dan kontras layar hape masing2 \n\nCatatan :\n1. Tidak menerima ganti warna ketika sudah dikirim, pastikan warna yang diorder sudah sesuai. Kontras layar hape memengaruhi warna foto, jadi setting pencahayaan ke cahaya normal saja. 98% warna sesuai dengan warna asli karena kami foto sendiri.\n2. Jika stock habis/kosong akan kami konfirmasi dulu, jika tidak ada respon akan kami kirim random.\n3. Garansi 100% uang kembali/tukar produk jika produk yang diterima cacat, koordinasikan via chat, jangan langsung ambil keputusan dan dimasukkan di review.\n4. Sebelum cekout, pastikan kembali, detail pesanan, alamat, pesanan (Supaya cepat sampai)\n\nHappy Shopping','MAHYRA DRESS',228000,241000,'SHP-23615938680',0,'Rayon Viscose Premium',NULL,NULL,1,0,NULL,1,23615938680,17019889,'https://shopee.co.id/product/17019889/23615938680',4.92,'TERSEDIA','[\"Fashion Muslim\", \"Pakaian Muslim Wanita\", \"Dress\", \"Gamis\"]','2026-06-27 07:04:13','2026-06-27 07:04:13'),(6,1,'Camila Dress . Gamis Rayon Homedress','camila-dress-gamis-rayon-homedress','Camila Dress\n\nDetail Dress\nBahan : Katun Rayon Premium\n(Bahan dingin, halus, dan menyerap keringat)\nLingkar Dada : -/+ 110 cm \nPanjang Seleting : -/+ 30 cm\nPanjang Baju : -/+ 140 cm\nPanjang lengan :-/+ 60 cm \nLingkar Ketiak : -/+ 50 cm\nLingkar Perut (Bagian rampel) : -/+ 100 cm\nLebar dari Perut ke bawah : -/+ 200 cm\n\nXXL :\nLingkar Dada : 120 \nPanjang Baju : 140 cm\n\nBusui Friendly Seleting \nRampel keliling di bagian pinggang \nPergelangan tangan karet\nTali Pinggang\nSaku bagian kanan \n\nCatatan :\n1. Tidak menerima ganti warna ketika sudah dikirim, pastikan warna yang diorder sudah sesuai. Kontras layar hape memengaruhi warna foto, jadi setting pencahayaan ke cahaya normal saja. 98% warna sesuai dengan warna asli karena kami foto sendiri.\n2. Jika stock habis/kosong akan kami konfirmasi dulu, jika tidak ada respon akan kami kirim random.\n3. Garansi 100% uang kembali/tukar produk jika produk yang diterima cacat, koordinasikan via chat, jangan langsung ambil keputusan dan dimasukkan di review.\n4. Sebelum cekout, pastikan kembali, detail pesanan, alamat, pesanan (Supaya cepat sampai)\n\nHappy Shopping \n#onesetrayon #onesetbusui #onesetbusuifriendly #onesetjogja #onesetmurah #onesetpajamas #onesetpiyama #onesetmotif #onesetkemeja #grosironeset #onesetgrosir #grosirpiyama #piyamagrosir #supplieroneset #supplieronesetpiyama #supplierpiyama #piyamamurah #piyamaset #setelankulot #dasterbusui #dasterrayon #dressrayon #dressbusui','Camila Dress',214000,244000,'SHP-12981423012',0,'Katun Rayon Premium',NULL,NULL,1,0,NULL,2,12981423012,17019889,'https://shopee.co.id/product/17019889/12981423012',4.89,'TERSEDIA','[\"Fashion Muslim\", \"Pakaian Muslim Wanita\", \"Dress\", \"Gamis\"]','2026-06-27 07:04:14','2026-06-27 07:04:14'),(7,3,'Yura Set . One Set Setelan Rayon Piyama','yura-set-one-set-setelan-rayon-piyama','Yura Set\n\nDetail Atasan \n- Panjang baju +/- 80 cm \n- Lingkar dada 112/114 cm\n- Panjang lengan 57 cm\n- Lingkar ketiak 50 cm\n- Tidak berkerah\n- Lengan kancing wudhu friendly \n- Busui friendly full kancing \n- Ada tali pinggang \n- Ada ruffle keliling pinggang \n- Sangat lebar jadi bumil friendly banget\n\nDetail Celana \n- Panjang celana : 95 cm\n- Lingkar paha : 70 cm\n- Panjang Pasak : 40 cm\n- Lingkar perut sampai 110 cm \n- Pinggang full karet\n- Ada saku \n\nBahan Rayon Premium\n(Dingin, halus, nyaman dan menyerap keringat) \n\nCatatan :\n1. Tidak menerima ganti warna ketika sudah dikirim, pastikan warna yang diorder s